<template>
  <div class="login">
    <div class="loginWrapper">
      <p>{{ title }}</p>
      <el-tabs v-model="activeName" style="padding-top:20px">
        <el-tab-pane label="帐号密码登录" name="first">
          <el-form :model="accountForm" :rules="accountFormRules" ref="accountForm" size="mini" label-position="top" label-width="80px">
            <el-form-item label="帐号：" prop="username">
              <el-input v-model="accountForm.username"></el-input>
            </el-form-item>
            <el-form-item label="密码：" prop="password">
              <el-input v-model="accountForm.password" type="password"></el-input>
            </el-form-item>
            <el-form-item style="text-align:center">
              <el-button class="loginButton" type="primary" @click="submitAccountForm('accountForm')">登录</el-button>
            </el-form-item>
          </el-form>
        </el-tab-pane>
        <el-tab-pane label="手机号登录" name="second">
          <el-form label-position="top" label-width="80px" :model="phoneForm" :rules="phoneFormRules" ref="phoneForm" size="mini">
            <el-form-item label="手机号：" prop="username">
              <el-input v-model="phoneForm.username"></el-input>
            </el-form-item>
            <el-form-item label="验证码：" class="VerificationCode" prop="dxcode">
              <el-input v-model="phoneForm.dxcode"></el-input>
              <el-button @click="sendSms" :disabled="isSendSms">{{ codeText }}</el-button>
            </el-form-item>
            <el-form-item style="text-align:center">
              <el-button class="loginButton" type="primary" @click="submitPhoneForm('phoneForm')">登录</el-button>
            </el-form-item>
          </el-form>
        </el-tab-pane>
      </el-tabs>
    </div>
  </div>
</template>

<script>
import workBGimage from "../assets/images/111.jpg";
import supervisionBGimage from "../assets/images/222.jpg";
import publicBGimage from "../assets/images/333.jpg";

export default {
  data() {
    const validateAccountFormUsername = (rule, value, callback) => {
      if (!value) {
        return callback(new Error("请输入帐号"));
      }
      return callback();
    };
    const validateAccountFormPassword = (rule, value, callback) => {
      if (!value) {
        return callback(new Error("请输入密码"));
      }
      return callback();
    };
    const validatephoneFormUsername = (rule, value, callback) => {
      if (!value) {
        return callback(new Error("请输入手机号"));
      }
      if (!/^1[0-9]\d{9}$/.test(value)) {
        return callback(new Error("请输入正确格式的手机号"));
      }
      return callback();
    };
    const validatephoneFormDxcodee = (rule, value, callback) => {
      if (!value) {
        return callback(new Error("请输入验证码"));
      }
      return callback();
    };
    return {
      tag: this.$route.query.tag || 1,
      title: "江苏省阳光食堂智慧工作平台",
      activeName: "first",
      codeText: "获取验证码",
      isSendSms: false,
      accountForm: {
        username: "",
        password: ""
      },
      phoneForm: {
        username: "",
        dxcode: "",
        dx: ""
      },
      accountFormRules: {
        username: [{ validator: validateAccountFormUsername, trigger: "blur" }],
        password: [{ validator: validateAccountFormPassword, trigger: "blur" }]
      },
      phoneFormRules: {
        username: [{ validator: validatephoneFormUsername, trigger: "blur" }],
        dxcode: [{ validator: validatephoneFormDxcodee, trigger: "blur" }]
      }
    };
  },
  mounted() {
    this.juageTags();
  },
  methods: {
    juageTags() {
      const obj = document.querySelector(".login");
      switch (+this.tag) {
        case 2:
          this.title = "江苏省阳光食堂智慧监管平台";
          obj.style.background = ` url('${supervisionBGimage}') no-repeat center`;
          obj.style.backgroundSize = "100% auto";
          break;
        case 3:
          this.title = "江苏省阳光食堂智慧公开平台";
          obj.style.background = ` url('${publicBGimage}') no-repeat center`;
          obj.style.backgroundSize = "100% auto";
          break;
        default:
          obj.style.background = ` url('${workBGimage}') no-repeat center`;
          obj.style.backgroundSize = "100% auto";
          break;
      }
    },
    submitAccountForm(formName) {
      this.$refs[formName].validate(valid => {
        if (valid) {
          this.$axios
            .post("/api", {
              username: this.accountForm.username,
              password: this.accountForm.password
            })
            .then(res => {
              console.log(res);
            });
        }
      });
    },
    sendSms() {
      this.$refs.phoneForm.validateField("username", err => {
        this.isSendSms = true;
        if (!err && this.isSendSms) {
          let time = 120;
          const timer = setInterval(() => {
            this.codeText = `${time}秒`;
            time--;
            if (time < 0) {
              this.codeText = "获取验证码";
              this.isSendSms = false;
              window.clearInterval(timer);
            }
          }, 1000);
        } else {
          this.isSendSms = false;
        }
      });
    },
    submitPhoneForm(formName) {
      this.$refs[formName].validate(valid => {
        if (valid) {
          console.log("提交了哦");
        }
      });
    }
  }
};
</script>

<style scoped lang="stylus">
.login {
  width: 100%;
  height: 100%;
  position: relative;
  overflow: hidden;

  .loginWrapper {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translateY(-50%) translateX(-50%);
    background: #fff;
    padding: 50px 50px 30px 50px;
    border-radius: 6px;
    box-shadow: 1px 1px 2px #eee;

    & p:first-child {
      color: #212121;
      font-size: 20px;
      font-weight: 800;
      line-height: 0;
      margin: 0 0 20px;
    }
  }
}
</style>



